    case CommandService.execute(params) do
      {:ok, result} ->
        conn
        |> put_status(:ok)
        |> json(%{
          success: true,
          data: result
        })

      {:error, %CommandService.CommandError{message: message, type: type}} ->
        status = case type do
          :security -> :forbidden
          :validation -> :bad_request
          :timeout -> :request_timeout
          _ -> :internal_server_error
